from agent import *from models.products import *def serialize_text(text):    text = text.replace('&#233;', 'é').replace('&#8232;', '').replace("", '').replace('', '').replace(' ', '').replace('', '').replace('', '').replace('', '').replace('﻿', '').replace('', '').replace('', '').replace('', '').replace('', '').replace('', ''). replace('', '').replace('', '').replace('', '').strip()    return textdef strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=10000)]    session.browser.use_new_parser = True    session.queue(Request('https://www.backpacker.com/gear-reviews/'), process_revlist, {})def process_revlist(data, context, session):    strip_namespace(data)    revs = data.xpath('//article//h3[contains(@class, "title")]/a')    for rev in revs:        title = rev.xpath('text()').string()        url = rev.xpath('@href').string()        session.queue(Request(url), process_review, dict(title=title, url=url))    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url), process_revlist, {})def process_review(data, context, session):    strip_namespace(data)    product = Product()    product.name = serialize_text(data.xpath('//p[*[contains(., "Model:")]]/text()[normalize-space()]').string() or context['title'].split('Gear Review: ')[-1])    product.url = data.xpath('//a[@class="tm-c-button"]/@href').string() or context['url']    product.category = 'Gear'    product.ssid = data.xpath('//article/@data-uuid').string()    manufacturer = data.xpath('//h3[*[contains(., "Brand:")]]/text()[normalize-space()]').string()    if manufacturer:        product.manufacturer = serialize_text(manufacturer)    review = Review()    review.title = serialize_text(context['title'])    review.ssid = product.ssid    review.url = context['url']    review.type = 'pro'    date = data.xpath('//span[contains(@class, "timestamp")]/time/@datetime').string()    if date:        review.date = date.split('T')[0]    authors = data.xpath('//a[@rel="author"]')    for author in authors:        author_name = serialize_text(author.xpath('strong/text()').string())        author_url = author.xpath('@href').string()        author_ssid = author_url.strip('/').split('/')[-1]        review.authors.append(Person(name=author_name, ssid=author_ssid, profile_url=author_url))    pros = data.xpath('//div[contains(@class, "in-article")]/p[regexp:test(., "^\s*pros\s*:", "i")]/text()').string()    if pros:        pros = serialize_text(pros).strip(' \n*-')        if 'pros:' in pros.lower():            pros = pros.split(': ')[-1].split(', ')            for pro in pros:                review.properties.append(ReviewProperty(type=ReviewPropertyType(name='cons'), value=pro.strip()))        elif pros:            review.properties.append(ReviewProperty(type=ReviewPropertyType(name='pros'), value=pros))    cons = data.xpath('//div[contains(@class, "in-article")]/p[regexp:test(., "^\s*cons\s*:", "i")]/text()').string()    if cons:        cons = serialize_text(cons).strip(' \n*-')        if 'cons:' in cons.lower():            cons = cons.split(': ')[-1].split(', ')            for con in cons:                review.properties.append(ReviewProperty(type=ReviewPropertyType(name='cons'), value=con.strip()))        elif cons:            review.properties.append(ReviewProperty(type=ReviewPropertyType(name='cons'), value=cons))    grade_overall = data.xpath('//div[contains(@class, "in-article")]/*[self::h1 or self::h2 or self::h3 or self::h4][preceding-sibling::*[self::h1 or self::h2 or self::h3 or self::h4][1][regexp:test(., "( Score| rating)", "i")]]/text()').string()    if grade_overall:        grade_overall = float(grade_overall.strip())        review.grades.append(Grade(name="Rating", value=grade_overall, best = 5.0, type='overall'))    summary = data.xpath('//div[@class="c-article-dek"]/p//text()[normalize-space()]').string(multiple=True)    if summary:        summary = serialize_text(summary)        if summary:            review.properties.append(ReviewProperty(type=ReviewPropertyType(name='summary'), value=summary))    excerpt = data.xpath('//div[contains(@class, "in-article")]/p[not(regexp:test(., "^\s*(\$\d*;|pros\s*:|cons\s*:)", "i"))][not(regexp:test(., "^\s*\*\s*Overall", "i"))][not(regexp:test(., "^\s*(Originally published|Published.*;)", "i"))]//text()[not(parent::*[regexp:test(., "^\s*(\$\d*;|pros\s*:|cons\s*:)", "i")])]').string(multiple=True)    if excerpt:        excerpt = serialize_text(excerpt)        if excerpt:            review.properties.append(ReviewProperty(type=ReviewPropertyType(name='excerpt'), value=excerpt))            product.reviews.append(review)            session.emit(product)